import express from 'express';
const router = express.Router();

// GET /projects/:projectId - Get project details
router.get('/:projectId', (req, res) => {
  const { projectId } = req.params;
  // Fetch and return project details from the service
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    sendError(res, 404, 'Not Found', 'Project not found');
  } else {
    res.json({ project });
  }
});

export default router;

import { randomUUID } from 'node:crypto';
import errors from '../../lib/errors';

const projects = [];

export const getProjectById = (projectId) => {
  return projects.find(p => p.id === projectId);
};

export const createProject = ({ name }) => {
  if (!name) throw new errors.BadRequestError('Name is required');
  const id = randomUUID();
  const project = { id, name };
  projects.push(project);
  return project;
};

import express from 'express';
const router = express.Router({ mergeParams: true });

// POST /projects/:projectId/members - Create a new member
router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    sendError(res, 400, 'Bad Request', 'User ID and role are required');
  } else {
    const member = membersService.createMember({ projectId: req.params.projectId, userId, role });
    res.status(201).json({ member });
  }
});

