import express from 'express';
const router = express.Router({ mergeParams: true });

// POST /projects/:projectId/tasks - Create a new task
router.post('/', (req, res) => {
  const { title, description } = req.body;
  if (!title || !description) {
    sendError(res, 400, 'Bad Request', 'Title and description are required');
  } else {
    const task = tasksService.createTask({ projectId: req.params.projectId, title, description });
    res.status(201).json({ task });
  }
});

// PATCH /projects/:projectId/tasks/:taskId - Update a task status
router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    sendError(res, 400, 'Bad Request', 'Invalid status');
  } else {
    const updatedTask = tasksService.updateTaskStatus({ taskId, status });
    res.json({ task: updatedTask });
  }
});

export default router;

import { randomUUID } from 'node:crypto';
import errors from '../../lib/errors';

const tasks = [];

export const createTask = ({ projectId, title, description }) => {
  if (!title || !description) throw new errors.BadRequestError('Title and description are required');
  const id = randomUUID();
  const task = { id, projectId, title, description, status: 'todo' };
  tasks.push(task);
  return task;
};

export const updateTaskStatus = ({ taskId, status }) => {
  const task = tasks.find(t => t.id === taskId);
  if (!task) throw new errors.NotFoundError('Task not found');
  task.status = status;
  return task;
};

